                try {
                    Q().fin(foo.bar);
                } catch (err) {
                    expect(err.message).toBe("Q can't apply finally callback");
                    threw = true;
                }

                expect(threw).toBe(true);
            });
        });

        describe("not a function", function () {
            it("should have a useful error", function () {
